import {State} from './State';

export interface TypedEventLike<E = any> {
    name: string;
    on: (handle: (x?: E) => void) => any;
    removeListener: (handle: (x?: E) => void) => any;
    emit: (x?: E) => any;
}

export interface TypedEventContainer<E = any> {
    event: TypedEventLike<E>;
    handler: (data?: E) => void;
}

export interface EventContainer {
    event: string;
    handler: (data?: any) => void;
}

export interface GlobalContainer<T> {
    event: T;
    destination: State;
    exceptions: State[];
}

export function createTypedEventTransitionName(event: TypedEventLike): string {
    return 'TEvent: ' + event.name;
}

export function createEventTransitionName(event: string): string {
    return 'Event: ' + event;
}
